import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Box, UserCheck, Search, Filter, Globe } from 'lucide-react';

const PanelCliente = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [ofertasFiltradas, setOfertasFiltradas] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  
  // Ubicación inicial profesional
  const [provinciaSel, setProvinciaSel] = useState('Tucumán');
  const [ciudadSel, setCiudadSel] = useState('San Miguel de Tucumán');
  const [zonaSel, setZonaSel] = useState('Todas las zonas');

  // Listado real de provincias de Argentina
  const provinciasArgentina = [
    'Buenos Aires', 'CABA', 'Catamarca', 'Chaco', 'Chubut', 'Córdoba', 'Corrientes', 
    'Entre Ríos', 'Formosa', 'Jujuy', 'La Pampa', 'La Rioja', 'Mendoza', 'Misiones', 
    'Neuquén', 'Río Negro', 'Salta', 'San Juan', 'San Luis', 'Santa Cruz', 
    'Santa Fe', 'Santiago del Estero', 'Tierra del Fuego', 'Tucumán'
  ].sort();

  // Simulación de base de datos de ciudades por provincia (esto luego puede ser una API)
  const ciudadesPorProvincia = {
    'Tucumán': ['San Miguel de Tucumán', 'Yerba Buena', 'Tafí Viejo', 'Concepción', 'Lules', 'Monteros'],
    'Salta': ['Salta Capital', 'Cafayate', 'Metán', 'Orán'],
    'Córdoba': ['Córdoba Capital', 'Villa Carlos Paz', 'Río Cuarto', 'Alta Gracia'],
    'CABA': ['Palermo', 'Recoleta', 'Caballito', 'Belgrano', 'San Telmo'],
    // ... se pueden añadir todas las que necesites
  };

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acumulador = [];

    locales.forEach(local => {
      const ofertasLocal = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      acumulador = [...acumulador, ...ofertasLocal.map(o => ({
        ...o,
        nombreLocal: local.nombre,
        zona: local.zona || 'Centro',
        ciudad: local.ciudad || 'San Miguel de Tucumán',
        provincia: local.provincia || 'Tucumán'
      }))];
    });

    setTodasLasOfertas(acumulador);
  }, []);

  useEffect(() => {
    let resultado = todasLasOfertas.filter(o => {
      const coincideBusqueda = o.producto.toLowerCase().includes(busqueda.toLowerCase());
      const coincideProvincia = o.provincia === provinciaSel;
      const coincideCiudad = ciudadSel === 'Todas' || o.ciudad === ciudadSel;
      const coincideZona = zonaSel === 'Todas las zonas' || o.zona === zonaSel;
      
      return coincideBusqueda && coincideProvincia && coincideCiudad && coincideZona;
    });
    setOfertasFiltradas(resultado);
  }, [busqueda, provinciaSel, ciudadSel, zonaSel, todasLasOfertas]);

  // Extraer zonas dinámicas de las ofertas existentes en la ciudad elegida
  const zonasDinamicas = ['Todas las zonas', ...new Set(
    todasLasOfertas
      .filter(o => o.provincia === provinciaSel && o.ciudad === ciudadSel)
      .map(o => o.zona)
  )];

  return (
    <div style={{ background: '#f4f7f6', minHeight: '100vh' }}>
      
      <div style={navUbicacion}>
        <div style={contenedorUbi}>
          {/* PROVINCIA */}
          <div style={ubiGroup}>
            <Globe size={18} color="#e67e22" />
            <div style={selectBox}>
              <label style={miniLabel}>Provincia</label>
              <select 
                value={provinciaSel} 
                onChange={(e) => {
                  setProvinciaSel(e.target.value);
                  setCiudadSel('Todas'); 
                }} 
                style={selectEstilo}
              >
                {provinciasArgentina.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
          </div>

          <div style={divisorV} />

          {/* CIUDAD */}
          <div style={ubiGroup}>
            <MapPin size={18} color="#e67e22" />
            <div style={selectBox}>
              <label style={miniLabel}>Ciudad / Localidad</label>
              <select 
                value={ciudadSel} 
                onChange={(e) => setCiudadSel(e.target.value)} 
                style={selectEstilo}
              >
                <option value="Todas">Todas las ciudades</option>
                {(ciudadesPorProvincia[provinciaSel] || []).map(c => (
                  <option key={c} value={c}>{c}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* BARRIOS / ZONAS */}
        <div style={zonaWrapper}>
          <div style={zonaScroll}>
            {zonasDinamicas.map(z => (
              <button 
                key={z} 
                onClick={() => setZonaSel(z)}
                style={zonaSel === z ? zonaBtnActive : zonaBtn}
              >
                {z}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ padding: '30px 5%' }}>
        {/* BUSCADOR */}
        <div style={searchContainer}>
          <Search size={22} color="#94a3b8" />
          <input 
            type="text" 
            placeholder={`Buscar en ${ciudadSel === 'Todas' ? provinciaSel : ciudadSel}...`} 
            style={inputBusqueda}
            onChange={(e) => setBusqueda(e.target.value)}
          />
          <Filter size={22} color="#1e293b" />
        </div>

        <div style={headerResultados}>
          <h2 style={tituloSeccion}>Ofertas en {ciudadSel === 'Todas' ? provinciaSel : ciudadSel}</h2>
          <span style={pillResultados}>{ofertasFiltradas.length} Disponibles</span>
        </div>
        
        <div style={gridPro}>
          {ofertasFiltradas.length > 0 ? (
            ofertasFiltradas.map(o => (
              <div key={o.id} style={cardPro}>
                <div style={ahorroBadge}>-{Math.round(((o.precioViejo - o.precioNuevo)/o.precioViejo)*100)}%</div>
                <div style={imgContainerPro}>
                   {o.imagen ? <img src={o.imagen} alt={o.producto} style={imgFull} /> : <Box size={40} color="#cbd5e1" />}
                </div>
                <div style={cuerpoCard}>
                  <p style={localTag}>{o.nombreLocal} • {o.zona}</p>
                  <h3 style={prodTitle}>{o.producto}</h3>
                  <div style={priceContainer}>
                    <span style={priceMain}>${o.precioNuevo}</span>
                    <span style={priceOff}>${o.precioViejo}</span>
                  </div>
                  <div style={stockRow}>
                    <div style={stockItem}><Box size={14} /> Stock: {o.stock}</div>
                    <div style={stockItem}><UserCheck size={14} /> Máx: {o.limitePorCliente}</div>
                  </div>
                  <button style={btnComprarPro}>
                    <ShoppingCart size={18} /> Reservar Oferta
                  </button>
                </div>
              </div>
            ))
          ) : (
            <div style={emptyStatePro}>
              <Box size={60} color="#cbd5e1" style={{marginBottom: '20px'}} />
              <h3>Aún no hay ofertas aquí</h3>
              <p>Estamos trabajando para traer los mejores descuentos a {ciudadSel === 'Todas' ? provinciaSel : ciudadSel}.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

/* --- ESTILOS --- */
const navUbicacion = { background: 'white', padding: '15px 5%', borderBottom: '1px solid #e2e8f0', position: 'sticky', top: 0, zIndex: 1000 };
const contenedorUbi = { display: 'flex', alignItems: 'center', background: '#fff', borderRadius: '16px', padding: '12px 20px', marginBottom: '20px', border: '1px solid #e2e8f0', boxShadow: '0 2px 4px rgba(0,0,0,0.02)' };
const ubiGroup = { display: 'flex', alignItems: 'center', gap: '12px', flex: 1 };
const selectBox = { display: 'flex', flexDirection: 'column', flex: 1 };
const miniLabel = { fontSize: '0.65rem', fontWeight: '800', color: '#94a3b8', textTransform: 'uppercase' };
const selectEstilo = { border: 'none', background: 'transparent', fontSize: '0.95rem', fontWeight: '700', color: '#1e293b', outline: 'none', cursor: 'pointer' };
const divisorV = { width: '1px', height: '30px', background: '#e2e8f0', margin: '0 25px' };

const zonaWrapper = { overflow: 'hidden' };
const zonaScroll = { display: 'flex', gap: '12px', overflowX: 'auto', paddingBottom: '5px', scrollbarWidth: 'none' };
const zonaBtn = { padding: '10px 20px', borderRadius: '14px', border: '1px solid #f1f5f9', background: '#f8fafc', whiteSpace: 'nowrap', cursor: 'pointer', fontSize: '0.85rem', fontWeight: '600', color: '#64748b', flexShrink: 0 };
const zonaBtnActive = { ...zonaBtn, background: '#e67e22', color: 'white', borderColor: '#e67e22' };

const searchContainer = { display: 'flex', alignItems: 'center', gap: '15px', background: 'white', padding: '18px 25px', borderRadius: '20px', border: '1px solid #e2e8f0' };
const inputBusqueda = { border: 'none', outline: 'none', flex: 1, fontSize: '1rem' };

const headerResultados = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', margin: '40px 0 25px 0' };
const tituloSeccion = { fontSize: '1.6rem', fontWeight: '800', color: '#1e293b', margin: 0 };
const pillResultados = { background: '#1e293b', color: 'white', padding: '6px 14px', borderRadius: '12px', fontSize: '0.8rem', fontWeight: 'bold' };

const gridPro = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '30px' };
const cardPro = { background: 'white', borderRadius: '28px', overflow: 'hidden', boxShadow: '0 4px 20px rgba(0,0,0,0.04)', position: 'relative' };
const ahorroBadge = { position: 'absolute', top: '20px', right: '20px', background: '#ef4444', color: 'white', padding: '6px 12px', borderRadius: '12px', fontSize: '0.8rem', fontWeight: '900', zIndex: 10 };
const imgContainerPro = { height: '220px', background: '#f8fafc', display: 'flex', justifyContent: 'center', alignItems: 'center' };
const imgFull = { width: '100%', height: '100%', objectFit: 'cover' };
const cuerpoCard = { padding: '25px' };
const localTag = { fontSize: '0.75rem', fontWeight: '700', color: '#e67e22', textTransform: 'uppercase', marginBottom: '8px' };
const prodTitle = { fontSize: '1.3rem', fontWeight: '700', color: '#1e293b', margin: '0 0 15px 0' };
const priceContainer = { display: 'flex', alignItems: 'baseline', gap: '12px', marginBottom: '20px' };
const priceMain = { fontSize: '2.2rem', fontWeight: '900', color: '#1e293b' };
const priceOff = { fontSize: '1.1rem', textDecoration: 'line-through', color: '#94a3b8' };
const stockRow = { display: 'flex', gap: '15px', marginBottom: '25px' };
const stockItem = { display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.8rem', color: '#64748b', background: '#f8fafc', padding: '6px 12px', borderRadius: '10px' };
const btnComprarPro = { width: '100%', padding: '16px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '18px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', justifyContent: 'center', gap: '10px' };
const emptyStatePro = { gridColumn: '1/-1', textAlign: 'center', padding: '100px 0', color: '#94a3b8' };

export default PanelCliente;
